module binary_to_gray(
    input [3:0] gray_code_in,
    output reg [3:0] gray
);

    always @(*) begin
        gray[3] = gray_code_in[3];
        gray[2] = gray_code_in[3] ^ gray_code_in[2];
        gray[1] = gray_code_in[2] ^ gray_code_in[1];
        gray[0] = gray_code_in[1] ^ gray_code_in[0];
    end

endmodule
